css:
/*【水色疗愈】作者：易碎蝶*/
/*本美化免费发布于QQ小群/部分dc社区，素材（除壁纸/上层装饰中的图片）皆为原创，禁止二传二改，外如果你是以其他渠道获得皆是二转，麻烦点个举报，支持原创*/

/*🍃←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/714/main/result.css");

body {
    font-family: "Swei D Lucy CJK SC";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 77px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background:  url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 40px;


    /* 层级控制 */
    z-index: 5;
    pointer-events: auto;

    /* 移除动画属性 */
    transform: none !important;
    animation: none !important;
}

/* 应用到您的顶栏装饰层 */
#top-bar::after {
    animation: gentleSwing 8s ease-in-out infinite; /* 8秒完成一次完整摇摆 */
    transform-origin: top center; /* 确保悬挂点在顶部中心 */
    /* 确保其他属性不变 */
    content: "";
    position: fixed;
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / contain;
    width: 190px;
    height: 200px;
    top: -67px;
    right: 2px;
    z-index: 6;
    pointer-events: none;
}


/* —————面板背景图———— */
.drawer-content {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 40px;
    height: 40px;
    background: transparent url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat;
    border: none;
    border-radius: 0;
    box-shadow: none;
    cursor: ew-resize;
    position: relative;
    z-index: 1;
}

/*——————最新消息箭头图标替换——————*/
/* ===== 隐藏原有字体图标 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; /* 双重保障隐藏图标 */
}

/* ===== 自定义箭头样式 ===== */
.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 60px;   /* 箭头图片宽度 */
  height: 40px;  /* 箭头图片高度 */
opacity: 1 !important; /* 默认闲时透明度 */
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 左箭头URL */
}


.fa-chevron-right {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 右箭头URL */
}

/* ===== 滑动计数器样式 ===== */
.swipes-counter {
  /* 文字样式 */
  color: var(--SmartThemeBodyColor);
  font-family: var(--mainFontFamily);
  font-size: 10px;
  font-weight: 540;

  /* 布局定位 */
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;

  /* 尺寸控制 */
  min-width: 0;
  height: var(--swipeCounterHeight); /* 高度变量 */
  padding: 0 40px;                 /* 水平内边距（右边箭头左右位置） */



  /* 间距控制 */
  margin: 
    var(--counter-vertical, 0)    /* 垂直间距，默认0 */
    var(--counter-horizonta, 0);  /* 水平间距，默认0 */
  margin-bottom: var(--swipeCounterMargin); /* 底部间距变量 */

  /* 备用定位方案 (需要时启用) */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 🍃装饰层模块
 * ==============================================*/
/* 🍃上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -135px; /* 上层装饰层【上下】(负值表示向上) */
  left: 4px; /* 上层装饰层【左右】 */
  width: 340.5px; /* 调整上层装饰层的【宽度/大小】 */
  height: 530px; /* 调整上层装饰层的【高度/大小】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -2; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 🍃下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -137px; /* 下层装饰层【上下】(负值表示向下) */
  right: -0px; /* 下层装饰层【左右】 */
  width: 348px; /* 调整下层装饰层的【宽度/大小】 */
  height: 157px; /* 调整下层装饰层的【高度/大小】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: -4; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————🍃文本边距调整——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 00;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 🍃可独立调整的边距系统 */

    --top-padding:1rem; /* 气泡顶部留白 */
    --bottom-padding: 3rem; /* 气泡底部留白 */
    --left-padding: 0.5rem; /* 气泡左边距 */
    --right-padding: 0.9rem; /* 气泡右边距 */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 1px; */
}






/*——————气泡设置——————*/

/* ==============================================
 * 1.🍃 气泡容器模块
 * ==============================================*/
.mes {
  color: #4B4E58 !important;      /* 保持文字纯白 */
   z-index: -3;
  max-width: 345px;/*【🍃宽度】*/
  width: 400%;/*【🍃宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 190px auto 100px;/*【AI和用户的气泡距离】*/
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}


/* ==============================================
 * 气泡页面头像框
 * ============================================== */

.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;

  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* 2. 🍃装饰框位置与大小调整核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 18%;/* 【上下】 */
  left: 20%;/* 【左右】 */
  width: 250%;  /* 【框宽度】 */
  height: 180%; /* 【框高度】 */


  display: block;

  /* ⭕️头像框链接放置处 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');/*←🍃*/
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;

  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ==============================================
 * 2. 🍃头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -86px;           /* 【控制头像在气泡上方的位置】 */
  left: 82%;            /* 【调整头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 🍃基础尺寸 - 可自定义修改 */
  width: 76px;           /* 头像宽度 */
  height: 66px;          /* 头像高度 */


  /* 外观样式 */
  overflow: hidden;
  border: 0px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0);
  transition: all 0.3s ease;

  /* 旋转效果 */
  transform: rotate(0deg); /* 顺时针旋转 */
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ==============================================
 * 4. 🍃楼层显示
 * ============================================== */
.mes .mesIDDisplay {

    position: fixed;  
    top: 200;           
    left: -305%;        /* 【楼层左右】 */
    transform: translateX(-50%); 
    z-index: 999;    
    margin-top: -92px; /* 【楼层上下】 */
   transform: translateX(-50%) rotate(0deg); /* 关键旋转效果 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.0); /* 【这里可以填楼层显示的背景色，最后一个数字区调整透明度】 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    z-index: 2;
    cursor: default;
    opacity: 0.5;
    font-size: calc(var(--mainFontSize) * 0.7);
    font-weight: 300;
    color: #758392; /* 【调整楼层显示的颜色】 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 1.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 🍃基础信息位置调整【时间戳等】
 * ============================================== */

/* 消息块容器 */
.mes_block {
  position: relative;
  padding-top: 0px;
  overflow: visible;
}

/* 角色名称 - 支持负值定位 */
.mes_block .ch_name {
  position: absolute; /* 改为绝对定位实现自由移动 */
  top: -33px; /* 上移20px（根据需要调整）*/
  left: 143px; /* 负值左移（根据需要调整）*/
  max-width: calc(100% - 105px);
  min-height: 0px;
  z-index: 10;
  font-size: 0.70em;
  font-weight: 300;
  letter-spacing: 0.9px;
  transform: rotate(0deg);

}



/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #758392 !important; /* 纯黑色 */
  text-shadow: none !important; /* 移除可能存在的文字阴影 */
  -webkit-text-stroke: 0 !important; /* 移除文字描边 */
}

/* 时间戳纯白色 */
.timestamp {
  color: #758392 !important; /* 纯白色 */
  opacity: 1 !important; /* 确保完全不透明 */
}



/* 固定时间戳 */
.timestamp {
  color: #3c4f61;
  position: absolute; /* 改为绝对定位 */
  top: -102px;         /* 距父容器顶部的距离 */
  left: -123px;          /* 固定在父容器左侧 */
  width: 100%;        /* 确保宽度不挤压 */
  pointer-events: none; /* 防止阻挡下方交互 */
  /* 新增字体样式 */
  font-size: 7px;     /* 设置字体大小（示例值） */
  font-weight: 300;    /* 设置字体粗细（示例值） */
/* 旋转效果 */
  transform: rotate(0deg); /* 顺时针旋转 */
}



/* 编辑按钮容器优化 */
.mes_buttons {
  position: relative;
  top: -16px; /*上下*/
  left: 50px;/*左右*/
  z-index: 30;
  padding: 20px; /* 增加内边距 */
  min-height: 36px; /* 确保最小高度 */
  box-sizing: border-box; /* 包含内边距 */
/* 旋转效果 */

  transform: rotate(0deg); /* 顺时针旋转 */
}



.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: drop-shadow(0px 0px 0px black);
    transition: 0.3s ease-in-out;

    /* 垂直位置控制 */
    position: relative;       /* 确保定位生效 */
    top: -0px;              /* 负数上移 | 正数下移 | 单位可用px/rem/vh等 */

    /* 水平位置控制 */
    right: 140px;            /* 负数右移 | 正数左移 | 单位可用px/rem/vw等 */
/* 旋转效果 */
  transform: rotate(0deg); /* 顺时针旋转 */
}

.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    /* 移除原阴影并添加白色阴影 */
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* 添加颜色设置为白色 */
    color: #758392 !important;
}

/* ==============================================
 * 🕒 计时器 & 🔤 字符计数显示组件
 * ============================================== */

.mes {
  position: relative; /* 创建定位上下文 */
}

/* 通用样式 */
.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; /* 使用固定定位确保不被遮挡 */
  z-index: 2147483647; /* 最高层级 (32位整数最大值) */
  cursor: default;
  opacity: 1;
  font-size: calc(var(--mainFontSize) * 0.6);
  font-weight: 300;
  text-align: center;
  padding: 0px 0px;
  border-radius: 0px;
  background: rgba(30, 30, 30, 0.0); /* 半透明白色背景 */
  backdrop-filter: blur(0px); /* 毛玻璃效果 */
  box-shadow: 0 2px 8px rgba(0,0,0,0.0);

  /* 默认位置 - 顶部居中 */
  top: 240px;
  left: 50%;
  transform: translateX(-50%);

  /* 颜色变量 - 便于单独修改 */
  --timer-color: #758392;
  --counter-color: #758392;
}

/* 单独控制计时器 */
.mes .mes_timer {
  z-index: 2;
  /* 位置调整 */
  top: var(--timer-top, -40.5px);  /* 【🍃计时器上下】 */
  left: var(--timer-left, 55%);/*【🍃计时器左右】*/
  transform: translateX(var(--timer-translate, -50%));

  /* 颜色控制 */
  color: var(--timer-color, #758392);
}

/* 单独控制字符计数 */
.mes .tokenCounterDisplay {
  z-index: 2;
  /* 位置调整 */
  top: var(--counter-top,-40.5px); /* 【🍃字符上下】 */
  left: var(--counter-left, -155%);/* 【🍃字符左右】 */
  transform: translateX(var(--counter-translate, -0%));
  /* 颜色控制 */
  color: var(--counter-color, #ffffff);
}
/* ==============================================
 * 🧠 外显思维链位置与颜色调整
 * ============================================== */

/* 推理头部容器 - 水色渐变卡片 */
.mes_reasoning_header {
  position: absolute;         /* 绝对定位悬浮效果 */
  z-index: 9999;              /* 顶层显示优先级 */
  top: -109px;                  /* 顶部定位基准 */
  left: 13%;                  /* 水平定位基准 */
  transform: translateX(-50%); /* 水平居中定位 */
  cursor: pointer;            /* 手型指针交互提示 */
  user-select: none;          /* 防止文本误选 */
  font-size: calc(var(--mainFontSize) * 0.75); /* 响应式字体缩放 */
  transition: all 0.3s ease;  /* 平滑状态过渡 */

  /* 水色渐变风格 */
  padding: 1px 9px;           /* 紧凑内边距 */
  background: linear-gradient(to bottom, #eef6fe, #ffffff); /* 水色到白色渐变 */
  border-radius: 0;           /* 直角设计 */
  color: #4a6a9c;             /* 深水蓝色文字 */

  /* 简约描边与阴影 */
  box-shadow: 
    0 0 0 1px rgba(255, 255, 255, 0.9),  /* 90%透明白色描边 */
    0 3px 8px rgba(237, 242, 249, 0.8);  /* 浅蓝色阴影 */
}

/* 悬停效果 - 轻微下压 */
.mes_reasoning_header:hover {
  transform: translateX(-50%) translateY(2px); 
  box-shadow: 
    0 0 0 1px rgba(255, 255, 255, 0.9),
    0 2px 5px rgba(237, 242, 249, 0.6);  /* 减弱的浅蓝阴影 */
}

/* 标题文字样式 */
.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;                   /* 垂直定位基准 */
  left: -9px;                 /* 水平微调对齐 */
  color: #3d5a80;             /* 深海蓝色文字 */
  font-weight: 600;           /* 增强可读性 */
  letter-spacing: 0.5px;      /* 字间距微调 */
}

/* 推理主体 - 水色便签风格 */
.mes_reasoning {
  position: relative;         
  top: -190px;                /* 垂直定位偏移 */
  display: block;
  margin: 215px 0;            /* 外边距保持空间 */

  /* 水色渐变卡片 */
  border-left: 2px solid #d1e0f0; /* 浅水蓝色左侧装饰线 */
  color: #4a6572;             /* 石板灰文字 */
  background: linear-gradient(to bottom, #c8d8ec, #ffffff); /* 水色到白色渐变 */

  /* 简约卡片效果 */
  box-shadow: 
    0 0 0 1px rgba(255, 255, 255, 0.9),  /* 90%透明白色描边 */
    0 5px 15px rgba(237, 242, 249, 0.7); /* 浅蓝色投影 */
  padding: 15px;              /* 内容内边距 */
  line-height: 1.6;           /* 舒适行高 */
}


.mes_reasoning_header_title {
  /* 隐藏原始文本 */
  font-size: 0; 
  color: transparent; 
}

.mes_reasoning_header_title::before {
  /*⭕️思维链文字diy */
  content: "˚₊‧ 水色药剂·ʚ ♫";
