/* 隐藏默认分割线 */
hr {
    all: unset !important; /* 清除所有默认样式 */
    display: block !important;
    visibility: visible !important;
    background-image: none !important; /* 移除渐变背景 */
    height: auto !important; /* 重置高度 */
    min-height: unset !important;
    margin: 0 !important;
    opacity: 1 !important;
    position: relative;
}

/* 添加自定义图片分割线 */
hr::after {
    content: "" !important;
    display: block !important;
    background-image: var(--divider-image, url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")) !important; /* 替换为你的图床URL */
