    background-position: var(--divider-position, center) !important; /* 图片位置：left/center/right */
    background-size: var(--divider-size, auto 100%) !important; /* 控制图片尺寸 */
    height: var(--divider-height, 61px) !important; /* 分割线高度 */
    width: var(--divider-width, 100%) !important; /* 分割线宽度 */
    margin: var(--divider-margin, 0px 0) !important; /* 上下边距 */
    opacity: var(--divider-opacity, 1) !important; /* 透明度控制 */
}
