/*——————输入框美化——————*/
#send_form {
  display: flex;
  flex-direction: column;
  width: 94.5%;
  max-width: 690px;
  margin: 0px auto;
  margin-bottom: 20px;
  padding: 7px 20px;
  border-radius: 0; /* 直角设计 */
  position: relative;
  overflow: hidden;

  /* 水色渐变背景（70%透明度） */
  background: linear-gradient(to bottom, 
    rgba(238, 246, 254, 0.8) 0%,  /* 顶部水色 */
    rgba(255, 255, 255, 0.8) 100% /* 底部白色 */
  );

  /* 白色描边与阴影 */
  box-shadow: 
    0 0 0 1px rgba(255, 255, 255, 0.9), /* 精致白色描边 */
    0 4px 15px rgba(237, 242, 249, 0.6); /* 柔和阴影 */

  /* 毛玻璃效果 */
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(20px); /* Safari兼容 */

  transition: all 0.4s ease;
  border: none;
}

#send_form:hover {
  /* 悬停状态增强效果 */
  box-shadow: 
    0 0 0 1.5px rgba(255, 255, 255, 0.95),
    0 6px 20px rgba(237, 242, 249, 0.75);
  transform: translateY(-3px);
}

#send_form > input[type="text"],
#send_form > .image-url-container > input {
  background: rgba(255, 255, 255, 0.65); /* 半透明白色背景 */
  color: #4a6572; /* 深海蓝灰色文字 */
  border: 1px solid rgba(232, 240, 254, 0.8); /* 水色边框 */
  border-radius: 4px; /* 轻微圆角 */
  padding: 12px 15px;

  /* 简约内部阴影 */
  box-shadow: inset 0 1px 2px rgba(203, 228, 255, 0.2);
}
