  content: '-';        /* 桃花符号 */
  font-size: 1.5em;
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #758392;         /* 纯白色图标 */
  text-shadow: 0 0 3px rgba(0,0,0,0.5); /* 黑色微光阴影 */
}

