/*————加载页面美化————*/
#load-spinner {
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center center;
    background-size: contain;
    /* 移除旋转动画，添加浮动动画 */
    animation: float 3s ease-in-out infinite; /* 2秒循环，平滑缓动 */
}

/* 创建上下浮动动画 */
@keyframes float {
    0%, 100% {
        transform: translateY(0); /* 起始和结束位置 */
    }
    50% {
        transform: translateY(-25px); /* 向上浮动 */
    }
}

/* 隐藏原有旋转图标 */
#load-spinner::before,
#load-spinner::after {
    display: none;
}

